var agg = new GlideAggregate('incident');
agg.addQuery('active', true);
agg.groupBy('priority');
agg.addAggregate('COUNT');
agg.query();
while (agg.next()) {
  gs.print('Priority ' + agg.getValue('priority') + ': ' + agg.getAggregate('COUNT'));
}

var gr = new GlideRecord('incident');
gr.addEncodedQuery('active=true^sys_updated_onRELATIVELT@dayofweek@ago@7');
gr.query();
while (gr.next()) {
  gs.print(gr.number + ' - ' + gr.sys_updated_on);
}

var dup = new GlideAggregate('cmdb_ci_computer');
dup.addNotNullQuery('serial_number');
dup.groupBy('serial_number');
dup.addAggregate('COUNT');
dup.addHaving('COUNT', '>', 1);
dup.query();
while (dup.next()) {
  gs.print(dup.getValue('serial_number') + ' -> ' + dup.getAggregate('COUNT'));
}

var gr = new GlideRecord('ecc_queue');
gr.addQuery('queue', 'output');
gr.addQuery('state', 'IN', 'ready,processing');
gr.orderByDesc('sys_created_on');
gr.setLimit(20);
gr.query();
while (gr.next()) {
  gs.print(gr.topic + ' | ' + gr.agent + ' | ' + gr.state + ' | ' + gr.sys_created_on);
}

var chg = new GlideRecord('change_request');
chg.addQuery('type', 'normal');
chg.addNotNullQuery('start_date');
chg.addNotNullQuery('end_date');
chg.addQuery('state', 'NOT IN', '3,4,7');
chg.query();
while (chg.next()) {
  var span = new GlideRecord('cmn_schedule_span');
  span.addQuery('type', 'blackout');
  span.addQuery('start_date_time', '<=', chg.end_date);
  span.addQuery('end_date_time', '>=', chg.start_date);
  span.query();
  if (span.next()) {
    gs.print(chg.number + ' overlaps blackout window ' + span.name);
  }
}

var gr = new GlideRecord('cmdb_sam_sw_install');
gr.addNotNullQuery('assigned_to');
gr.addQuery('assigned_to.active', false);
gr.query();
while (gr.next()) {
  gs.print(gr.getDisplayValue('software_model') + ' | ' + gr.getDisplayValue('installed_on') + ' | ' + gr.getDisplayValue('assigned_to'));
}

var gr = new GlideRecord('alm_hardware');
gr.addQuery('install_status', '6');
gr.addNullQuery('stockroom');
gr.query();
while (gr.next()) {
  gs.print(gr.asset_tag + ' | ' + gr.getDisplayValue('model'));
}
